10	export function loadEnvironment(): EnvironmentConfig {
11	  return {
12	    port: parseInt(process.env.PORT || '3000', 10),
13	    databaseUrl: process.env.DATABASE_URL || 'mysql://tripforge:tripforge@db:3306/tripforge',
14	    jwtSecret: process.env.JWT_SECRET || 'change_me_in_production',
15	    encryptionKey: process.env.ENCRYPTION_KEY || 'change_me_32_chars_minimum_here_x',
