4	export const traceStore = new AsyncLocalStorage<{ traceId: string }>();
5	
6	export function getTraceId(): string | undefined {
7	  return traceStore.getStore()?.traceId;
8	}
9	
10	const traceFormat = winston.format((info) => {
11	  const traceId = getTraceId();
12	  if (traceId) {
13	    info.traceId = traceId;
