1	import { Request, Response, NextFunction } from 'express';
2	import { v4 as uuidv4 } from 'uuid';
3	import { traceStore } from '../utils/logger';
4	import { logger } from '../utils/logger';
5	
6	export function auditMiddleware(req: Request, res: Response, next: NextFunction): void {
7	  const traceId = (req.headers['x-trace-id'] as string) || (req.headers['x-request-id'] as string) || uuidv4();
8	
9	  res.setHeader('X-Trace-Id', traceId);
10	  res.setHeader('X-Request-Id', traceId);
11	
12	  traceStore.run({ traceId }, () => {
13	    const startTime = Date.now();
14	
15	    res.on('finish', () => {
16	      const duration = Date.now() - startTime;
17	      logger.info('request completed', {
18	        method: req.method,
19	        path: req.originalUrl,
20	        statusCode: res.statusCode,
21	        duration,
22	        traceId,
23	      });
24	    });
25	
26	    next();
27	  });
28	}
