1	export class AppError extends Error {
2	  public readonly statusCode: number;
3	  public readonly code: string;
4	  public readonly details?: unknown;
5	
6	  constructor(statusCode: number, code: string, message: string, details?: unknown) {
7	    super(message);
8	    this.statusCode = statusCode;
9	    this.code = code;
10	    this.details = details;
11	    Object.setPrototypeOf(this, AppError.prototype);
12	  }
13	}
