15	export const VALIDATION_ERROR = 'VALIDATION_ERROR';
16	export const UNAUTHORIZED = 'UNAUTHORIZED';
17	export const FORBIDDEN = 'FORBIDDEN';
18	export const NOT_FOUND = 'NOT_FOUND';
19	export const CONFLICT = 'CONFLICT';
20	export const IDEMPOTENCY_CONFLICT = 'IDEMPOTENCY_CONFLICT';
21	export const RATE_LIMITED = 'RATE_LIMITED';
22	export const INTERNAL_ERROR = 'INTERNAL_ERROR';
