1	import { Prisma } from '../models/prisma';
2	import { getPrisma } from '../config/database';
3	import {
4	  AppError,
5	  NOT_FOUND,
6	  FORBIDDEN,
7	  CONFLICT,
8	  VALIDATION_ERROR,
9	} from '../utils/errors';
10	import ExcelJS from 'exceljs';
11	import { parse } from 'csv-parse/sync';
12	
13	/* ---------- Types ---------- */
14	
15	interface RowError {
16	  rowNumber: number;
17	  field: string | null;
18	  message: string;
19	  rawData: Record<string, unknown> | null;
20	}
21	
22	interface ValidatedRow {
23	  rowNumber: number;
24	  data: Record<string, unknown>;
25	  valid: boolean;
26	  errors: RowError[];
27	}
28	
29	/* ---------- Template Definitions ---------- */
30	
31	const RESOURCE_COLUMNS = [
32	  { header: 'name', key: 'name', width: 30 },
33	  { header: 'type', key: 'type', width: 15 },
34	  { header: 'streetLine', key: 'streetLine', width: 40 },
35	  { header: 'city', key: 'city', width: 20 },
36	  { header: 'region', key: 'region', width: 20 },
37	  { header: 'country', key: 'country', width: 20 },
38	  { header: 'latitude', key: 'latitude', width: 15 },
39	  { header: 'longitude', key: 'longitude', width: 15 },
40	  { header: 'minDwellMinutes', key: 'minDwellMinutes', width: 18 },
41	];
42	
43	const ITINERARY_COLUMNS = [
44	  { header: 'title', key: 'title', width: 30 },
45	  { header: 'destination', key: 'destination', width: 30 },
46	  { header: 'startDate', key: 'startDate', width: 15 },
47	  { header: 'endDate', key: 'endDate', width: 15 },
48	  { header: 'status', key: 'status', width: 15 },
49	];
50	
51	const RESOURCE_REQUIRED_FIELDS = ['name', 'type'];
52	const ITINERARY_REQUIRED_FIELDS = ['title'];
53	
54	/* ---------- Helpers ---------- */
55	
56	function getColumnsForEntity(entityType: string) {
57	  if (entityType === 'resources') return RESOURCE_COLUMNS;
58	  if (entityType === 'itineraries') return ITINERARY_COLUMNS;
59	  throw new AppError(400, VALIDATION_ERROR, `Unsupported entity type: ${entityType}`);
60	}
61	
62	function getRequiredFields(entityType: string): string[] {
63	  if (entityType === 'resources') return RESOURCE_REQUIRED_FIELDS;
64	  if (entityType === 'itineraries') return ITINERARY_REQUIRED_FIELDS;
65	  return [];
66	}
67	
68	function normalizeHeaders(headers: string[]): string[] {
69	  return headers.map((h) => h.trim().replace(/\s+/g, ''));
70	}
71	
72	function validateResourceRow(row: Record<string, unknown>, rowNumber: number): RowError[] {
73	  const errors: RowError[] = [];
74	
75	  if (row.latitude !== undefined && row.latitude !== null && row.latitude !== '') {
76	    const lat = Number(row.latitude);
77	    if (isNaN(lat) || lat < -90 || lat > 90) {
78	      errors.push({ rowNumber, field: 'latitude', message: 'Latitude must be a number between -90 and 90', rawData: row });
79	    }
80	  }
81	
82	  if (row.longitude !== undefined && row.longitude !== null && row.longitude !== '') {
83	    const lng = Number(row.longitude);
84	    if (isNaN(lng) || lng < -180 || lng > 180) {
85	      errors.push({ rowNumber, field: 'longitude', message: 'Longitude must be a number between -180 and 180', rawData: row });
86	    }
87	  }
88	
89	  if (row.minDwellMinutes !== undefined && row.minDwellMinutes !== null && row.minDwellMinutes !== '') {
90	    const dwell = Number(row.minDwellMinutes);
91	    if (isNaN(dwell) || dwell < 0 || !Number.isInteger(dwell)) {
92	      errors.push({ rowNumber, field: 'minDwellMinutes', message: 'minDwellMinutes must be a non-negative integer', rawData: row });
93	    }
94	  }
95	
96	  const validTypes = ['attraction', 'restaurant', 'hotel', 'transport', 'activity'];
97	  if (row.type && !validTypes.includes(String(row.type).toLowerCase())) {
98	    errors.push({ rowNumber, field: 'type', message: `type must be one of: ${validTypes.join(', ')}`, rawData: row });
99	  }
100	
101	  return errors;
102	}
103	
104	function validateItineraryRow(row: Record<string, unknown>, rowNumber: number): RowError[] {
105	  const errors: RowError[] = [];
106	
107	  if (row.startDate && isNaN(Date.parse(String(row.startDate)))) {
108	    errors.push({ rowNumber, field: 'startDate', message: 'startDate must be a valid date', rawData: row });
109	  }
110	
111	  if (row.endDate && isNaN(Date.parse(String(row.endDate)))) {
112	    errors.push({ rowNumber, field: 'endDate', message: 'endDate must be a valid date', rawData: row });
113	  }
114	
115	  const validStatuses = ['draft', 'published', 'archived'];
116	  if (row.status && !validStatuses.includes(String(row.status).toLowerCase())) {
117	    errors.push({ rowNumber, field: 'status', message: `status must be one of: ${validStatuses.join(', ')}`, rawData: row });
118	  }
119	
120	  return errors;
121	}
122	
123	function parseFileToRows(
124	  fileBuffer: Buffer,
125	  fileName: string,
126	): Record<string, unknown>[] {
127	  const ext = fileName.split('.').pop()?.toLowerCase();
128	
129	  if (ext === 'csv') {
130	    const records = parse(fileBuffer, {
131	      columns: true,
132	      skip_empty_lines: true,
133	      trim: true,
134	    }) as Record<string, unknown>[];
135	    return records;
136	  }
137	
138	  // For Excel, we handle it separately in the async function
139	  throw new AppError(400, VALIDATION_ERROR, 'Use parseExcelToRows for Excel files');
140	}
141	
142	async function parseExcelToRows(fileBuffer: Buffer): Promise<Record<string, unknown>[]> {
143	  const workbook = new ExcelJS.Workbook();
144	  await workbook.xlsx.load(fileBuffer as unknown as ExcelJS.Buffer);
145	  const worksheet = workbook.worksheets[0];
146	  if (!worksheet) throw new AppError(400, VALIDATION_ERROR, 'Excel file has no worksheets');
147	
148	  const rows: Record<string, unknown>[] = [];
149	  const headers: string[] = [];
150	
151	  worksheet.eachRow((row, rowNumber) => {
152	    if (rowNumber === 1) {
153	      row.eachCell((cell, colNumber) => {
154	        headers[colNumber - 1] = String(cell.value ?? '').trim();
155	      });
156	      return;
157	    }
158	
159	    const record: Record<string, unknown> = {};
160	    row.eachCell((cell, colNumber) => {
161	      const header = headers[colNumber - 1];
162	      if (header) {
163	        record[header] = cell.value;
164	      }
165	    });
166	    rows.push(record);
167	  });
168	
169	  return rows;
170	}
171	
172	/* ---------- Exports ---------- */
173	
174	export async function downloadTemplate(entityType: string): Promise<Buffer> {
175	  const columns = getColumnsForEntity(entityType);
176	
177	  const workbook = new ExcelJS.Workbook();
178	  workbook.creator = 'TripForge';
179	  workbook.created = new Date();
180	
181	  const sheet = workbook.addWorksheet(entityType);
182	  sheet.columns = columns;
183	
184	  // Style the header row
185	  const headerRow = sheet.getRow(1);
186	  headerRow.font = { bold: true };
187	  headerRow.commit();
188	
189	  const buffer = await workbook.xlsx.writeBuffer();
190	  return Buffer.from(buffer);
191	}
192	
193	export async function uploadAndValidate(
194	  userId: string,
195	  file: { buffer: Buffer; originalname: string },
196	  entityType: string,
197	  idempotencyKey: string,
198	  deduplicationKey?: string,
199	) {
200	  const prisma = getPrisma();
201	
202	  // Check idempotency - return existing batch if key already used
203	  const existingBatch = await prisma.importBatch.findUnique({
204	    where: { idempotencyKey },
205	    include: { errors: true },
206	  });
207	  if (existingBatch) {
208	    return existingBatch;
209	  }
210	
211	  getColumnsForEntity(entityType); // validates entity type
212	  const requiredFields = getRequiredFields(entityType);
213	
214	  // Parse file
215	  const ext = file.originalname.split('.').pop()?.toLowerCase();
216	  let rows: Record<string, unknown>[];
217	
218	  if (ext === 'csv') {
219	    rows = parseFileToRows(file.buffer, file.originalname);
220	  } else if (ext === 'xlsx' || ext === 'xls') {
221	    rows = await parseExcelToRows(file.buffer);
222	  } else {
223	    throw new AppError(400, VALIDATION_ERROR, 'Unsupported file format. Use CSV or Excel (.xlsx)');
224	  }
225	
226	  if (rows.length === 0) {
227	    throw new AppError(400, VALIDATION_ERROR, 'File contains no data rows');
228	  }
229	
230	  // Validate each row
231	  const validatedRows: ValidatedRow[] = [];
232	  const allErrors: RowError[] = [];
233	
234	  for (let i = 0; i < rows.length; i++) {
235	    const rowNumber = i + 2; // +2 for 1-indexed + header row
236	    const row = rows[i];
237	    const rowErrors: RowError[] = [];
238	
239	    // Required field checks
240	    for (const field of requiredFields) {
241	      const value = row[field];
242	      if (value === undefined || value === null || String(value).trim() === '') {
243	        rowErrors.push({
244	          rowNumber,
245	          field,
246	          message: `${field} is required`,
247	          rawData: row,
248	        });
249	      }
250	    }
251	
252	    // Type-specific validation
253	    if (entityType === 'resources') {
254	      rowErrors.push(...validateResourceRow(row, rowNumber));
255	    } else if (entityType === 'itineraries') {
256	      rowErrors.push(...validateItineraryRow(row, rowNumber));
257	    }
258	
259	    validatedRows.push({
260	      rowNumber,
261	      data: row,
262	      valid: rowErrors.length === 0,
263	      errors: rowErrors,
264	    });
265	    allErrors.push(...rowErrors);
266	  }
267	
268	  // Deduplication check against DB
269	  const dedupKey = deduplicationKey;
270	  if (entityType === 'resources') {
271	    const dedupFields = dedupKey ? dedupKey.split('+') : ['name', 'streetLine', 'city'];
272	    for (const vr of validatedRows) {
273	      if (!vr.valid) continue;
274	
275	      const where: Record<string, unknown> = {};
276	      let canDedup = true;
277	      for (const f of dedupFields) {
278	        const val = vr.data[f];
279	        if (val === undefined || val === null || String(val).trim() === '') {
280	          canDedup = false;
281	          break;
282	        }
283	        where[f] = String(val).trim();
284	      }
285	
286	      if (canDedup) {
287	        const existing = await prisma.resource.findFirst({ where });
288	        if (existing) {
289	          const err: RowError = {
290	            rowNumber: vr.rowNumber,
291	            field: dedupFields.join('+'),
292	            message: `Duplicate: a resource with the same ${dedupFields.join(', ')} already exists`,
293	            rawData: vr.data,
294	          };
295	          vr.errors.push(err);
296	          vr.valid = false;
297	          allErrors.push(err);
298	        }
299	      }
300	    }
301	  }
302	
303	  const successRows = validatedRows.filter((r) => r.valid).length;
304	  const errorRows = validatedRows.filter((r) => !r.valid).length;
305	
306	  // Create batch with validated data stored as JSON
307	  const batch = await prisma.importBatch.create({
308	    data: {
309	      userId,
310	      entityType,
311	      status: 'validated',
312	      totalRows: rows.length,
313	      successRows,
314	      errorRows,
315	      idempotencyKey,
316	      rollbackUntil: new Date(Date.now() + 10 * 60 * 1000), // 10 minutes from now
317	      validatedData: JSON.parse(JSON.stringify(validatedRows)),
318	    },
319	  });
320	
321	  // Store row-level errors
322	  if (allErrors.length > 0) {
323	    await prisma.importError.createMany({
324	      data: allErrors.map((e) => ({
325	        batchId: batch.id,
326	        rowNumber: e.rowNumber,
327	        field: e.field,
328	        message: e.message,
329	        rawData: (e.rawData ?? undefined) as Prisma.InputJsonValue | undefined,
330	      })),
331	    });
332	  }
333	
334	  return prisma.importBatch.findUnique({
335	    where: { id: batch.id },
336	    include: { errors: true },
337	  });
338	}
339	
340	export async function commitBatch(batchId: string, userId: string) {
341	  const prisma = getPrisma();
342	
343	  const batch = await prisma.importBatch.findUnique({
344	    where: { id: batchId },
345	    include: { errors: true },
346	  });
347	  if (!batch) throw new AppError(404, NOT_FOUND, 'Import batch not found');
348	  if (batch.userId !== userId) throw new AppError(403, FORBIDDEN, 'Access denied');
349	  if (batch.status === 'completed') throw new AppError(409, CONFLICT, 'Batch already committed');
350	  if (batch.status === 'rolled_back') throw new AppError(409, CONFLICT, 'Batch has been rolled back');
351	  if (batch.status !== 'validated') {
352	    throw new AppError(409, CONFLICT, `Cannot commit batch with status: ${batch.status}`);
353	  }
354	
355	  const validatedRows = batch.validatedData as ValidatedRow[] | null;
356	  if (!validatedRows || validatedRows.length === 0) {
357	    throw new AppError(400, VALIDATION_ERROR, 'No validated data to commit');
358	  }
359	
360	  const validRows = validatedRows.filter((r) => r.valid);
361	  if (validRows.length === 0) {
362	    throw new AppError(400, VALIDATION_ERROR, 'No valid rows to commit');
363	  }
364	
365	  const importedIds: string[] = [];
366	
367	  if (batch.entityType === 'resources') {
368	    for (const row of validRows) {
369	      const data = row.data;
370	      const resource = await prisma.resource.create({
371	        data: {
372	          name: String(data.name),
373	          type: String(data.type).toLowerCase(),
374	          streetLine: data.streetLine ? String(data.streetLine) : null,
375	          city: data.city ? String(data.city) : null,
376	          region: data.region ? String(data.region) : null,
377	          country: data.country ? String(data.country) : null,
378	          latitude: data.latitude !== undefined && data.latitude !== null && data.latitude !== ''
379	            ? Number(data.latitude)
380	            : null,
381	          longitude: data.longitude !== undefined && data.longitude !== null && data.longitude !== ''
382	            ? Number(data.longitude)
383	            : null,
384	          minDwellMinutes: data.minDwellMinutes
385	            ? Number(data.minDwellMinutes)
386	            : 30,
387	        },
388	      });
389	      importedIds.push(resource.id);
390	    }
391	  } else if (batch.entityType === 'itineraries') {
392	    for (const row of validRows) {
393	      const data = row.data;
394	      const itinerary = await prisma.itinerary.create({
395	        data: {
396	          ownerId: userId,
397	          title: String(data.title),
398	          destination: data.destination ? String(data.destination) : null,
399	          startDate: data.startDate ? new Date(String(data.startDate)) : null,
400	          endDate: data.endDate ? new Date(String(data.endDate)) : null,
401	          status: data.status ? String(data.status).toLowerCase() : 'draft',
402	        },
403	      });
404	      importedIds.push(itinerary.id);
405	    }
406	  }
407	
408	  // Update batch status and store imported IDs for potential rollback
409	  const updatedBatch = await prisma.importBatch.update({
410	    where: { id: batchId },
411	    data: {
412	      status: 'completed',
413	      successRows: importedIds.length,
414	      completedAt: new Date(),
415	      validatedData: JSON.parse(JSON.stringify({
416	        rows: validatedRows,
417	        importedIds,
418	      })) as Prisma.InputJsonValue,
419	    },
420	    include: { errors: true },
421	  });
422	
423	  return updatedBatch;
424	}
425	
426	export async function rollbackBatch(batchId: string, userId: string) {
427	  const prisma = getPrisma();
428	
429	  const batch = await prisma.importBatch.findUnique({ where: { id: batchId } });
430	  if (!batch) throw new AppError(404, NOT_FOUND, 'Import batch not found');
431	  if (batch.userId !== userId) throw new AppError(403, FORBIDDEN, 'Access denied');
432	  if (batch.status !== 'completed') {
433	    throw new AppError(409, CONFLICT, `Cannot rollback batch with status: ${batch.status}`);
434	  }
435	
436	  // Check rollback window
437	  if (new Date() > batch.rollbackUntil) {
438	    throw new AppError(409, CONFLICT, 'Rollback window has expired (10 minutes after commit)');
439	  }
440	
441	  const batchData = batch.validatedData as { importedIds?: string[] } | null;
442	  const importedIds = batchData?.importedIds ?? [];
443	
444	  if (importedIds.length > 0) {
445	    if (batch.entityType === 'resources') {
446	      await prisma.resource.deleteMany({
447	        where: { id: { in: importedIds } },
448	      });
449	    } else if (batch.entityType === 'itineraries') {
450	      await prisma.itinerary.deleteMany({
451	        where: { id: { in: importedIds } },
452	      });
453	    }
454	  }
455	
456	  return prisma.importBatch.update({
457	    where: { id: batchId },
458	    data: {
459	      status: 'rolled_back',
460	    },
461	    include: { errors: true },
462	  });
463	}
