26	async function createVersion(itineraryId: string, userId: string) {
27	  const prisma = getPrisma();
28	
29	  // Get current items as snapshot
30	  const items = await prisma.itineraryItem.findMany({
31	    where: { itineraryId },
32	    orderBy: [{ dayNumber: 'asc' }, { startTime: 'asc' }],
33	  });
34	
35	  // Determine next version number
36	  const lastVersion = await prisma.itineraryVersion.findFirst({
37	    where: { itineraryId },
38	    orderBy: { versionNumber: 'desc' },
39	  });
40	  const nextNumber = lastVersion ? lastVersion.versionNumber + 1 : 1;
41	
42	  // Compute diff from previous version
43	  let diffMetadata: Record<string, unknown> | null = null;
44	  if (lastVersion) {
45	    const prevSnapshot = lastVersion.snapshot as Array<Record<string, unknown>>;
46	    const currentIds = new Set(items.map((i) => i.id));
47	    const prevIds = new Set(prevSnapshot.map((i) => i.id as string));
48	
49	    const added = items.filter((i) => !prevIds.has(i.id)).map((i) => i.id);
50	    const removed = prevSnapshot.filter((i) => !currentIds.has(i.id as string)).map((i) => i.id as string);
51	    const modified = items
52	      .filter((i) => prevIds.has(i.id))
53	      .filter((cur) => {
54	        const prev = prevSnapshot.find((p) => p.id === cur.id);
55	        if (!prev) return false;
56	        return (
57	          prev.startTime !== cur.startTime ||
58	          prev.endTime !== cur.endTime ||
59	          prev.dayNumber !== cur.dayNumber ||
60	          prev.resourceId !== cur.resourceId ||
61	          prev.notes !== cur.notes ||
62	          prev.position !== cur.position
63	        );
64	      })
65	      .map((i) => i.id);
66	
67	    diffMetadata = { added, removed, modified };
68	  }
69	
70	  return prisma.itineraryVersion.create({
71	    data: {
72	      itineraryId,
73	      versionNumber: nextNumber,
74	      snapshot: JSON.parse(JSON.stringify(items)),
75	      diffMetadata: (diffMetadata as Prisma.InputJsonValue) ?? undefined,
76	      createdBy: userId,
77	    },
78	  });
79	}
80	
81	async function validateItem(
82	  itineraryId: string,
83	  dayNumber: number,
84	  startTime: string,
85	  endTime: string,
86	  resourceId: string,
87	  excludeItemId?: string,
88	) {
89	  const prisma = getPrisma();
90	  const startMin = timeToMinutes(startTime);
91	  const endMin = timeToMinutes(endTime);
92	
93	  if (startMin >= endMin) {
94	    throw new AppError(400, VALIDATION_ERROR, 'startTime must be before endTime');
95	  }
96	
97	  // Load resource with hours and closures
98	  const resource = await prisma.resource.findUnique({
99	    where: { id: resourceId },
100	    include: { hours: true, closures: true },
101	  });
102	  if (!resource) throw new AppError(404, NOT_FOUND, 'Resource not found');
103	
104	  // 1. Min dwell time check
105	  const durationMinutes = endMin - startMin;
106	  if (durationMinutes < resource.minDwellMinutes) {
107	    throw new AppError(
108	      400,
109	      VALIDATION_ERROR,
110	      `Duration (${durationMinutes}min) is less than minimum dwell time (${resource.minDwellMinutes}min)`,
111	    );
112	  }
113	
114	  // 2. Closure date check — need itinerary start date to compute actual date
115	  const itinerary = await prisma.itinerary.findUnique({ where: { id: itineraryId } });
116	  if (!itinerary) throw new AppError(404, NOT_FOUND, 'Itinerary not found');
117	
118	  if (itinerary.startDate) {
119	    const actualDate = new Date(itinerary.startDate);
120	    actualDate.setDate(actualDate.getDate() + (dayNumber - 1));
121	    // Normalize to date-only for comparison
122	    const dateStr = actualDate.toISOString().split('T')[0];
123	
124	    const closure = resource.closures.find((c) => {
125	      const closureStr = new Date(c.date).toISOString().split('T')[0];
126	      return closureStr === dateStr;
127	    });
128	    if (closure) {
129	      throw new AppError(
130	        400,
131	        VALIDATION_ERROR,
132	        `Resource is closed on this date${closure.reason ? ': ' + closure.reason : ''}`,
133	      );
134	    }
135	
136	    // 3. Business hours check
137	    const dayOfWeek = actualDate.getDay();
138	    const hoursForDay = resource.hours.filter((h) => h.dayOfWeek === dayOfWeek);
139	    if (hoursForDay.length > 0) {
140	      const withinAnyWindow = hoursForDay.some((h) => {
141	        const openMin = timeToMinutes(h.openTime);
142	        const closeMin = timeToMinutes(h.closeTime);
143	        return startMin >= openMin && endMin <= closeMin;
144	      });
145	      if (!withinAnyWindow) {
146	        throw new AppError(400, VALIDATION_ERROR, 'Item time falls outside business hours');
147	      }
148	    }
149	  }
150	
151	  // 4. Load existing items on same day for overlap / buffer / travel checks
152	  const existingItems = await prisma.itineraryItem.findMany({
153	    where: {
154	      itineraryId,
155	      dayNumber,
156	      ...(excludeItemId ? { id: { not: excludeItemId } } : {}),
157	    },
158	    include: { resource: true },
159	    orderBy: { startTime: 'asc' },
160	  });
161	
162	  const BUFFER_MINUTES = 15;
163	
164	  for (const item of existingItems) {
165	    const existStart = timeToMinutes(item.startTime);
166	    const existEnd = timeToMinutes(item.endTime);
167	
168	    // 5. Overlap detection
169	    if (startMin < existEnd && endMin > existStart) {
170	      throw new AppError(409, CONFLICT, 'Time slot overlaps with an existing item');
171	    }
172	
173	    // 6. 15-minute buffer
174	    if (
175	      (startMin >= existEnd && startMin < existEnd + BUFFER_MINUTES) ||
176	      (endMin > existStart - BUFFER_MINUTES && endMin <= existStart)
177	    ) {
178	      throw new AppError(409, CONFLICT, 'Items must have at least a 15-minute buffer between them');
179	    }
180	  }
181	
182	  // 7. Travel time from previous item
183	  // Find the item that ends right before our start
184	  const previousItem = existingItems
185	    .filter((i) => timeToMinutes(i.endTime) <= startMin)
186	    .sort((a, b) => timeToMinutes(b.endTime) - timeToMinutes(a.endTime))[0];
187	
188	  if (previousItem) {
189	    const travelTime = await prisma.travelTimeMatrix.findFirst({
190	      where: {
191	        fromResourceId: previousItem.resourceId,
192	        toResourceId: resourceId,
193	      },
194	    });
195	
196	    if (travelTime) {
197	      const prevEnd = timeToMinutes(previousItem.endTime);
198	      const gap = startMin - prevEnd;
199	      if (gap < travelTime.travelMinutes) {
200	        throw new AppError(
201	          409,
202	          CONFLICT,
203	          `Insufficient travel time from previous item (need ${travelTime.travelMinutes}min, have ${gap}min)`,
204	        );
205	      }
206	    }
207	  }
208	}
