66	function spawnAdapter(executable: string, args: string[], input: string): Promise<string> {
67	  return new Promise((resolve, reject) => {
68	    if (!ALLOWED_EXECUTABLES.some((e) => executable.startsWith(e))) {
69	      reject(new Error(`Executable not in allowlist: ${executable}`));
70	      return;
71	    }
