136	/**
137	 * Deterministic mock inference: produces stable output from input hash.
138	 * Used as fallback when real adapter runtime is not available.
139	 */
140	function mockInferFn(input: Record<string, unknown>, config: ModelConfig | null): AdapterResult {
141	  const inputStr = JSON.stringify(input, Object.keys(input).sort());
142	  const hash = crypto.createHash('md5').update(inputStr).digest();
143	
144	  // Generate deterministic prediction value from input
145	  const predictionValue = hash.readUInt16BE(0) / 65535; // 0..1
146	  const confidence = 0.5 + (hash.readUInt16BE(2) / 65535) * 0.5; // 0.5..1.0
147	
148	  // Generate feature contributions from configured features or input keys
149	  const features = config?.features ?? Object.keys(input);
150	  const topFeatures: { feature: string; contribution: number }[] = [];
151	
152	  let remainingContribution = 1.0;
153	  for (let i = 0; i < Math.min(features.length, 5); i++) {
154	    const featureHash = crypto
155	      .createHash('md5')
156	      .update(`${inputStr}:${features[i]}`)
157	      .digest();
158	    const contribution =
159	      i < features.length - 1
160	        ? (featureHash.readUInt16BE(0) / 65535) * remainingContribution * 0.6
161	        : remainingContribution;
162	    topFeatures.push({
163	      feature: features[i],
164	      contribution: Math.round(contribution * 1000) / 1000,
165	    });
166	    remainingContribution -= contribution;
167	  }
168	
169	  // Sort by contribution descending
170	  topFeatures.sort((a, b) => b.contribution - a.contribution);
171	
172	  return {
173	    prediction: Math.round(predictionValue * 100) / 100,
174	    confidence: Math.round(confidence * 1000) / 1000,
175	    topFeatures,
