179	/**
180	 * Safely evaluate a simple condition of the form "input.field op value".
181	 * Only supports comparison operators and field access — no arbitrary code execution.
182	 */
183	function safeEvaluateCondition(condition: string, input: Record<string, unknown>): boolean {
184	  // Parse "input.field op value" patterns only
185	  const match = condition.match(/^input\.(\w+)\s*(>=|<=|===|!==|>|<)\s*(.+)$/);
186	  if (!match) return false;
187	
188	  const [, field, op, rawValue] = match;
189	  const fieldValue = input[field];
190	
191	  // Parse the comparison value
192	  let compareValue: unknown;
193	  const trimmed = rawValue.trim();
194	  if (trimmed === 'true') compareValue = true;
195	  else if (trimmed === 'false') compareValue = false;
196	  else if (/^-?\d+(\.\d+)?$/.test(trimmed)) compareValue = Number(trimmed);
197	  else if (/^['"].*['"]$/.test(trimmed)) compareValue = trimmed.slice(1, -1);
198	  else return false;
199	
200	  switch (op) {
201	    case '>': return Number(fieldValue) > Number(compareValue);
202	    case '<': return Number(fieldValue) < Number(compareValue);
203	    case '>=': return Number(fieldValue) >= Number(compareValue);
204	    case '<=': return Number(fieldValue) <= Number(compareValue);
205	    case '===': return fieldValue === compareValue;
206	    case '!==': return fieldValue !== compareValue;
