62	/* ---------- Send Notification ---------- */
63	
64	export async function sendNotification(
65	  userId: string,
66	  type: string,
67	  templateCode?: string,
68	  variables?: Record<string, string>,
69	  subject?: string,
70	  message?: string,
71	) {
72	  const prisma = getPrisma();
73	
74	  // Check user exists
75	  const user = await prisma.user.findUnique({ where: { id: userId } });
76	  if (!user) throw new AppError(404, NOT_FOUND, 'User not found');
77	
78	  // Check blacklist and daily cap
79	  const settings = await prisma.userNotificationSetting.findUnique({
80	    where: { userId },
81	  });
82	
83	  if (settings?.blacklisted) {
84	    throw new AppError(403, FORBIDDEN, 'User has been blacklisted from notifications');
85	  }
86	
87	  if (settings && settings.dailySent >= settings.dailyCap) {
88	    throw new AppError(429, 'RATE_LIMITED', 'Daily notification cap reached');
89	  }
90	
91	  // Resolve template if provided
92	  let resolvedSubject = subject ?? null;
93	  let resolvedMessage = message ?? '';
94	  let templateId: string | null = null;
95	
96	  if (templateCode) {
97	    const template = await prisma.notificationTemplate.findUnique({
98	      where: { code: templateCode },
99	    });
100	    if (!template) throw new AppError(404, NOT_FOUND, `Template "${templateCode}" not found`);
101	
102	    templateId = template.id;
103	    const vars = variables ?? {};
104	    resolvedSubject = template.subject ? resolveTemplate(template.subject, vars) : resolvedSubject;
105	    resolvedMessage = resolveTemplate(template.body, vars);
106	  }
107	
108	  if (!resolvedMessage) {
109	    throw new AppError(400, VALIDATION_ERROR, 'Either templateCode or message must be provided');
110	  }
111	
112	  // Create notification and outbox entry in transaction
113	  const result = await prisma.$transaction(async (tx) => {
114	    const notification = await tx.notification.create({
115	      data: {
116	        userId,
117	        type,
118	        templateId,
119	        subject: resolvedSubject,
120	        message: resolvedMessage,
121	      },
122	    });
123	
124	    await tx.outboxMessage.create({
125	      data: {
126	        notificationId: notification.id,
127	        status: 'pending',
128	      },
129	    });
130	
131	    // Increment daily sent counter
132	    if (settings) {
133	      await tx.userNotificationSetting.update({
134	        where: { userId },
135	        data: { dailySent: settings.dailySent + 1 },
136	      });
137	    } else {
138	      await tx.userNotificationSetting.create({
139	        data: {
140	          userId,
141	          dailySent: 1,
142	        },
143	      });
144	    }
145	
146	    return notification;
147	  });
148	
149	  return result;
150	}
