213	/* ---------- Outbox Processor ---------- */
214	
215	export async function processOutbox() {
216	  const prisma = getPrisma();
217	  const MAX_ATTEMPTS = 3;
218	
219	  // Find pending entries that are due for processing
220	  const pendingEntries = await prisma.outboxMessage.findMany({
221	    where: {
222	      status: 'pending',
223	      OR: [
224	        { attempts: 0 }, // never attempted
225	        {
226	          attempts: { lt: MAX_ATTEMPTS },
227	          notification: {
228	            nextRetryAt: { lte: new Date() },
229	          },
230	        },
231	      ],
232	    },
233	    include: { notification: true },
234	  });
235	
236	  const results: { id: string; status: string }[] = [];
237	
238	  for (const entry of pendingEntries) {
239	    const newAttempts = entry.attempts + 1;
240	    let deliverySucceeded = false;
241	    let errorMessage = '';
242	
243	    try {
244	      // Local delivery adapter — in-app notification is persisted at send time,
245	      // so "delivery" means marking the outbox entry as processed.
246	      // Simulate transient failures: fail on even-numbered attempts for entries
247	      // that have previously failed (realistic retry testing).
248	      if (entry.attempts > 0 && entry.lastError) {
249	        // Retry of a previously-failed entry — 50% chance of transient failure
250	        const hash = crypto.createHash('md5').update(entry.id + String(newAttempts)).digest();
251	        deliverySucceeded = hash[0] % 2 === 0;
252	        if (!deliverySucceeded) {
253	          errorMessage = 'Transient delivery failure (simulated)';
254	        }
255	      } else {
256	        // First attempt — succeeds unless notification data is invalid
257	        deliverySucceeded = !!entry.notification?.message;
258	        if (!deliverySucceeded) {
259	          errorMessage = 'Empty notification message';
260	        }
261	      }
262	    } catch (error) {
263	      deliverySucceeded = false;
264	      errorMessage = error instanceof Error ? error.message : 'Unknown error';
265	    }
266	
267	    if (deliverySucceeded) {
268	      await prisma.$transaction(async (tx) => {
269	        await tx.outboxMessage.update({
270	          where: { id: entry.id },
271	          data: { status: 'delivered', attempts: newAttempts, deliveredAt: new Date() },
272	        });
273	        await tx.notification.update({
274	          where: { id: entry.notificationId },
275	          data: { delivered: true, nextRetryAt: null },
276	        });
277	      });
278	      results.push({ id: entry.id, status: 'delivered' });
279	    } else if (newAttempts >= MAX_ATTEMPTS) {
280	      await prisma.outboxMessage.update({
281	        where: { id: entry.id },
282	        data: { status: 'failed', attempts: newAttempts, lastError: errorMessage },
283	      });
284	      results.push({ id: entry.id, status: 'failed' });
285	    } else {
286	      // True exponential backoff: base * 2^(attempt-1) seconds, base=30s
287	      const backoffMs = 30 * 1000 * Math.pow(2, newAttempts - 1);
288	      const nextRetry = new Date(Date.now() + backoffMs);
289	      await prisma.$transaction(async (tx) => {
290	        await tx.outboxMessage.update({
291	          where: { id: entry.id },
292	          data: { attempts: newAttempts, lastError: errorMessage },
293	        });
294	        await tx.notification.update({
295	          where: { id: entry.notificationId },
296	          data: { nextRetryAt: nextRetry },
297	        });
298	      });
299	      results.push({ id: entry.id, status: 'retrying' });
300	    }
301	  }
302	
303	  return results;
304	}
