7	// --- Safe rule evaluator (mirrors safeEvaluateCondition from model.service.ts) ---
8	function safeEvaluateCondition(condition: string, input: Record<string, unknown>): boolean {
9	  const match = condition.match(/^input\.(\w+)\s*(>=|<=|===|!==|>|<)\s*(.+)$/);
10	  if (!match) return false;
11	  const [, field, op, rawValue] = match;
12	  const fieldValue = input[field];
13	  let compareValue: unknown;
14	  const trimmed = rawValue.trim();
15	  if (trimmed === 'true') compareValue = true;
16	  else if (trimmed === 'false') compareValue = false;
17	  else if (/^-?\d+(\.\d+)?$/.test(trimmed)) compareValue = Number(trimmed);
18	  else if (/^['"].*['"]$/.test(trimmed)) compareValue = trimmed.slice(1, -1);
19	  else return false;
20	  switch (op) {
21	    case '>': return Number(fieldValue) > Number(compareValue);
22	    case '<': return Number(fieldValue) < Number(compareValue);
23	    case '>=': return Number(fieldValue) >= Number(compareValue);
24	    case '<=': return Number(fieldValue) <= Number(compareValue);
25	    case '===': return fieldValue === compareValue;
26	    case '!==': return fieldValue !== compareValue;
27	    default: return false;
28	  }
29	}
