1	import crypto from 'crypto';
2	import { env } from '../config/environment';
3	
4	const ALGORITHM = 'aes-256-gcm';
5	const IV_LENGTH = 16;
6	const AUTH_TAG_LENGTH = 16;
7	
8	function getKey(): Buffer {
9	  const keyStr = env.encryptionKey;
10	  return crypto.createHash('sha256').update(keyStr).digest();
11	}
12	
13	export function encrypt(plaintext: string): string {
14	  const key = getKey();
15	  const iv = crypto.randomBytes(IV_LENGTH);
16	  const cipher = crypto.createCipheriv(ALGORITHM, key, iv);
17	
18	  let encrypted = cipher.update(plaintext, 'utf8');
19	  encrypted = Buffer.concat([encrypted, cipher.final()]);
20	  const authTag = cipher.getAuthTag();
21	
22	  const combined = Buffer.concat([iv, authTag, encrypted]);
23	  return combined.toString('base64');
24	}
25	
26	export function decrypt(ciphertext: string): string {
27	  const key = getKey();
28	  const combined = Buffer.from(ciphertext, 'base64');
29	
30	  const iv = combined.subarray(0, IV_LENGTH);
31	  const authTag = combined.subarray(IV_LENGTH, IV_LENGTH + AUTH_TAG_LENGTH);
32	  const encrypted = combined.subarray(IV_LENGTH + AUTH_TAG_LENGTH);
33	
34	  const decipher = crypto.createDecipheriv(ALGORITHM, key, iv);
35	  decipher.setAuthTag(authTag);
36	
37	  let decrypted = decipher.update(encrypted);
38	  decrypted = Buffer.concat([decrypted, decipher.final()]);
39	  return decrypted.toString('utf8');
40	}
41	
42	export function hashSha256(input: string): string {
43	  return crypto.createHash('sha256').update(input).digest('hex');
44	}
