    data: {
      itineraryId,
      versionNumber: nextNumber,
      snapshot: JSON.parse(JSON.stringify(snapshot)) as Prisma.InputJsonValue,
      diffMetadata: (diffMetadata as Prisma.InputJsonValue) ?? undefined,
      createdBy: userId,
    },
  });
}"}

