    prisma.importBatch.findUnique.mockResolvedValue({
      id: 'b1',
      userId: 'user-1',
      status: 'validated',
      entityType: 'resources',
      rollbackUntil: new Date(Date.now() + 60_000),
      validatedData: { importedIds: [] },
