5	/**
6	 * Per-request correlation middleware.
7	 *
8	 * Canonical request id is `requestId`. We accept either `X-Request-Id` (the
9	 * documented header) or the legacy `X-Trace-Id` from clients, generate a
10	 * fresh UUID if neither is present, and:
11	 *
12	 *   - Echo the value back as both `X-Request-Id` (canonical) and `X-Trace-Id`
13	 *     (legacy alias) on every response so existing clients keep working.
14	 *   - Stash it in AsyncLocalStorage so error responses, audit log rows, and
15	 *     structured log entries can pick it up without threading it through
16	 *     every call.
17	 */
18	export function auditMiddleware(req: Request, res: Response, next: NextFunction): void {
19	  const requestId =
20	    (req.headers['x-request-id'] as string) ||
21	    (req.headers['x-trace-id'] as string) ||
22	    uuidv4();
23	
24	  // Canonical header — what the spec promises and what tests assert on.
25	  res.setHeader('X-Request-Id', requestId);
26	  // Legacy alias — keeps any existing client code working.
27	  res.setHeader('X-Trace-Id', requestId);
28	
29	  requestStore.run({ requestId }, () => {
30	    const startTime = Date.now();
31	
32	    res.on('finish', () => {
33	      const duration = Date.now() - startTime;
34	      logger.info('request completed', {
35	        method: req.method,
36	        path: req.originalUrl,
37	        statusCode: res.statusCode,
38	        duration,
39	        requestId,
40	      });
41	    });
42	
43	    next();
44	  });
45	}
