const yaml = require('js-yaml');
const fs = require('fs');
const docs = yaml.safeLoad(fs.readFileSync('../docs/api-spec.md', 'utf8'));
console.log('docs paths:', Object.keys(docs.paths || {}).length);

require('ts-node/register');
const { apiSpec } = require('./src/config/swagger');
const docsOps = new Set();
for (const [p, methods] of Object.entries(docs.paths || {})) for (const m of Object.keys(methods)) if (['get','post','patch','put','delete'].includes(m.toLowerCase())) docsOps.add(m.toUpperCase()+' '+p);
const swaggerOps = new Set();
for (const [p, methods] of Object.entries(apiSpec.paths || {})) for (const m of Object.keys(methods)) if (['get','post','patch','put','delete'].includes(m.toLowerCase())) swaggerOps.add(m.toUpperCase()+' '+p);
console.log('IN SWAGGER NOT DOCS:', [...swaggerOps].filter(o => !docsOps.has(o)));
console.log('IN DOCS NOT SWAGGER:', [...docsOps].filter(o => !swaggerOps.has(o)));
